package main

import (
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"

	"github.com/gin-gonic/gin"
)

func main() {
	r := gin.Default()

	r.Use(ForwardMid)

	// Create a catchall route
	r.Any("/*proxyPath", Reverse)

	if err := r.Run(":8888"); err != nil {
		panic(err)
	}
}

func ForwardMid(c *gin.Context) {
	// !!! adapt to your request header set
	if v, ok := c.Request.Header["Forward"]; ok {
		if v[0] == "ok" {
			resp, err := http.DefaultTransport.RoundTrip(c.Request)
			if err != nil {
				http.Error(c.Writer, err.Error(), http.StatusServiceUnavailable)
				c.Abort()
				return
			}
			defer func() { _ = resp.Body.Close() }()
			copyHeader(c.Writer.Header(), resp.Header)
			c.Writer.WriteHeader(resp.StatusCode)
			_, _ = io.Copy(c.Writer, resp.Body)
			c.Abort()
			return
		}
	}

	c.Next()
}

func copyHeader(dst, src http.Header) {
	for k, vv := range src {
		for _, v := range vv {
			dst.Add(k, v)
		}
	}
}

func Reverse(c *gin.Context) {
	remote, _ := url.Parse("http://xxx.xxx.xxx")
	proxy := httputil.NewSingleHostReverseProxy(remote)
	proxy.Director = func(req *http.Request) {
		req.Header = c.Request.Header
		req.Host = remote.Host
		req.URL.Host = remote.Host
		req.URL.Scheme = remote.Scheme
	}
	proxy.ServeHTTP(c.Writer, c.Request)
}

package gen

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"os"
	"path/filepath"
)

const manifestFileName = ".genmanifest.json"

type genManifest struct {
	Version int `json:"version"`
	Mode    uint `json:"mode"`
	Tables  map[string]genManifestTable `json:"tables,omitempty"`
	Files   map[string]string          `json:"files,omitempty"`
}

type genManifestTable struct {
	ModelStructName string `json:"model_struct_name"`
	QueryStructName string `json:"query_struct_name"`
	FileName        string `json:"file_name"`
}

func loadManifest(dir string) (*genManifest, string, error) {
	path := filepath.Join(dir, manifestFileName)
	b, err := os.ReadFile(path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return &genManifest{Version: 1, Tables: map[string]genManifestTable{}, Files: map[string]string{}}, path, nil
		}
		return nil, "", err
	}
	var m genManifest
	if err := json.Unmarshal(b, &m); err != nil {
		return nil, "", err
	}
	if m.Version == 0 {
		m.Version = 1
	}
	if m.Tables == nil {
		m.Tables = map[string]genManifestTable{}
	}
	if m.Files == nil {
		m.Files = map[string]string{}
	}
	return &m, path, nil
}

func saveManifest(path string, m *genManifest) error {
	b, err := json.MarshalIndent(m, "", "  ")
	if err != nil {
		return err
	}
	b = append(b, '\n')
	return os.WriteFile(path, b, 0640)
}

func sha256Hex(b []byte) string {
	sum := sha256.Sum256(b)
	return hex.EncodeToString(sum[:])
}

package main

import (
	"log"
	"os"

	"github.com/gin-gonic/gin"

	"github.com/gothinkster/golang-gin-realworld-example-app/articles"
	"github.com/gothinkster/golang-gin-realworld-example-app/common"
	"github.com/gothinkster/golang-gin-realworld-example-app/users"
	"gorm.io/gorm"
)

func Migrate(db *gorm.DB) {
	users.AutoMigrate()
	db.AutoMigrate(&articles.ArticleModel{})
	db.AutoMigrate(&articles.TagModel{})
	db.AutoMigrate(&articles.FavoriteModel{})
	db.AutoMigrate(&articles.ArticleUserModel{})
	db.AutoMigrate(&articles.CommentModel{})
}

func main() {

	db := common.Init()
	Migrate(db)
	sqlDB, err := db.DB()
	if err != nil {
		log.Println("failed to get sql.DB:", err)
	} else {
		defer sqlDB.Close()
	}

	r := gin.Default()

	// Disable automatic redirect for trailing slashes
	// This prevents POST body from being lost during redirects
	r.RedirectTrailingSlash = false

	v1 := r.Group("/api")
	users.UsersRegister(v1.Group("/users"))
	v1.Use(users.AuthMiddleware(false))
	articles.ArticlesAnonymousRegister(v1.Group("/articles"))
	articles.TagsAnonymousRegister(v1.Group("/tags"))
	users.ProfileRetrieveRegister(v1.Group("/profiles"))

	v1.Use(users.AuthMiddleware(true))
	users.UserRegister(v1.Group("/user"))
	users.ProfileRegister(v1.Group("/profiles"))

	articles.ArticlesRegister(v1.Group("/articles"))

	testAuth := r.Group("/api/ping")

	testAuth.GET("/", func(c *gin.Context) {
		c.JSON(200, gin.H{
			"message": "pong",
		})
	})

	// Get port from environment variable or use default
	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}
	if err := r.Run(":" + port); err != nil {
		log.Fatal("failed to start server:", err)
	}
}

